import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Card, icon } from 'decantr/components';

code.example:
function UnlockGateBlur({ preview, requiredTier, onSubscribe, creatorName }) {
  const { div, img, p, span } = tags;

  return div({ class: css('_relative _overflow[hidden]') },
    div({ class: css('_aspect[16/9] _bgmuted/10') },
      preview ? img({ src: preview, class: css('_wfull _hfull _objcover _blur[12px] _scale[1.05]') }) :
        div({ class: css('_wfull _hfull _bgGradient _from[#F97316/20] _to[#8B5CF6/20]') })
    ),
    div({ class: css('_absolute _inset0 _bg[rgba(250,249,247,0.85)] _dark:bg[rgba(28,25,23,0.9)] _flex _col _center _p6 _tc') },
      div({ class: css('_w16 _h16 _r[50%] _bgbg _shadow _flex _center _mb4') },
        icon('lock', { size: '28', class: css('_fgmuted') })
      ),
      p({ class: css('_heading4 _mb2') }, 'Exclusive Content'),
      p({ class: css('_fgmuted _mb4 _maxw[320px]') },
        'Subscribe to ', span({ class: css('_fontmedium _fgfg') }, requiredTier.name),
        ' to unlock this content from ', creatorName
      ),
      div({ class: css('_flex _aic _gap2 _mb4') },
        div({ class: css('_w3 _h3 _r1'), style: `background:${requiredTier.color || '#F97316'}` }),
        span({ class: css('_fontmedium') }, requiredTier.name),
        span({ class: css('_fgmuted') }, ' - $', requiredTier.monthlyPrice, '/mo')
      ),
      Button({ variant: 'primary', size: 'lg', class: css('studio-glow'), onclick: onSubscribe },
        'Subscribe to Unlock'
      )
    )
  );
}

