function UnlockGateTeaser({ teaserContent, requiredTier, onSubscribe }) {
  const { div, p } = tags;

  return div({ class: css('_relative') },
    div({ class: css('_maxh[200px] _overflow[hidden]') },
      p({ class: css('_whitespace[pre-wrap]') }, teaserContent)
    ),
    div({ class: css('_absolute _bottom0 _left0 _right0 _h[200px] _bg[linear-gradient(transparent,var(--d-bg))]') }),
    div({ class: css('_absolute _bottom0 _left0 _right0 _tc _pb4') },
      Card({ class: css('studio-card _p4 _inline-flex _flex _col _aic _shadow') },
        p({ class: css('_fontmedium _mb2') }, 'Continue reading...'),
        p({ class: css('_textsm _fgmuted _mb3') }, 'Subscribe to ', requiredTier.name, ' for full access'),
        Button({ variant: 'primary', onclick: onSubscribe },
          icon('unlock', { size: '16', class: css('_mr2') }), 'Unlock Full Post'
        )
      )
    )
  );
}

